40: import static org.apache.kafka.common.requests.OffsetsForLeaderEpochResponse.UNDEFINED_EPOCH;
41: import static org.apache.kafka.common.requests.OffsetsForLeaderEpochResponse.UNDEFINED_EPOCH_OFFSET;
42: 
43: /**
44:  * Represents a cache of (LeaderEpoch => Offset) mappings for a particular replica.
45:  * <p>
46:  * Leader Epoch = epoch assigned to each leader by the controller.
47:  * Offset = offset of the first message in each epoch.
48:  * <p>
49:  * Note that {@link #truncateFromStartAsyncFlush},{@link #truncateFromEndAsyncFlush} flush the epoch-entry changes to checkpoint asynchronously.
50:  * Hence, it is instantiater's responsibility to ensure restoring the cache to the correct state after instantiating
51:  * this class from checkpoint (which might contain stale epoch entries right after instantiation).
52:  */
53: public final class LeaderEpochFileCache {
54:     private final TopicPartition topicPartition;
55:     private final LeaderEpochCheckpointFile checkpoint;
56:     private final Scheduler scheduler;
57:     private final Logger log;
58: 
59:     private final ReentrantReadWriteLock lock = new ReentrantReadWriteLock();
60:     private final TreeMap<Integer, EpochEntry> epochs = new TreeMap<>();
61: 
62: 
63:     /**
64:      * @param topicPartition the associated topic partition
65:      * @param checkpoint     the checkpoint file
66:      * @param scheduler      the scheduler to use for async I/O operations
67:      */
68:     public LeaderEpochFileCache(TopicPartition topicPartition, LeaderEpochCheckpointFile checkpoint, Scheduler scheduler) {
69:         this.checkpoint = checkpoint;
70:         this.topicPartition = topicPartition;
71:         this.scheduler = scheduler;
72:         LogContext logContext = new LogContext("[LeaderEpochCache " + topicPartition + "] ");
73:         log = logContext.logger(LeaderEpochFileCache.class);
74:         checkpoint.read().forEach(this::assign);
75:     }
76: 
77:     /**
78:      * Instantiate a new LeaderEpochFileCache with provided epoch entries instead of from the backing checkpoint file.
79:      * The provided epoch entries are expected to be no less fresh than the checkpoint file.
80:      * @param epochEntries the current epoch entries
81:      * @param topicPartition the associated topic partition
82:      * @param checkpoint the checkpoint file
83:      * @param scheduler the scheduler to use for async I/O operations
84:      */
85:     private LeaderEpochFileCache(List<EpochEntry> epochEntries,
86:                                  TopicPartition topicPartition,
87:                                  LeaderEpochCheckpointFile checkpoint,
88:                                  Scheduler scheduler) {
89:         this.checkpoint = checkpoint;
90:         this.topicPartition = topicPartition;
91:         this.scheduler = scheduler;
92:         LogContext logContext = new LogContext("[LeaderEpochCache " + topicPartition + "] ");
93:         log = logContext.logger(LeaderEpochFileCache.class);
94:         for (EpochEntry entry : epochEntries) {
95:             epochs.put(entry.epoch, entry);
96:         }
97:     }
98: 
99:     /**
100:      * Assigns the supplied Leader Epoch to the supplied Offset
101:      * Once the epoch is assigned it cannot be reassigned
102:      */
103:     public void assign(int epoch, long startOffset) {
104:         EpochEntry entry = new EpochEntry(epoch, startOffset);
105:         if (assign(entry)) {
106:             log.debug("Appended new epoch entry {}. Cache now contains {} entries.", entry, epochs.size());
107:             writeToFile();
108:         }
109:     }
110: 
111:     public void assign(List<EpochEntry> entries) {
112:         entries.forEach(entry -> {
113:             if (assign(entry)) {
114:                 log.debug("Appended new epoch entry {}. Cache now contains {} entries.", entry, epochs.size());
115:             }
116:         });
117:         if (!entries.isEmpty()) writeToFile();
118:     }
119: 
120:     private boolean isUpdateNeeded(EpochEntry entry) {
121:         return latestEntry().map(epochEntry -> entry.epoch != epochEntry.epoch || entry.startOffset < epochEntry.startOffset).orElse(true);
122:     }
123: 
124:     private boolean assign(EpochEntry entry) {
125:         if (entry.epoch < 0 || entry.startOffset < 0) {
126:             throw new IllegalArgumentException("Received invalid partition leader epoch entry " + entry);
127:         }
128: 
